import androidx.preference.PreferenceCategory
import androidx.preference.PreferenceScreen
import com.ichi2.anki.R
import com.ichi2.anki.cardviewer.CommandGroup
import com.ichi2.anki.cardviewer.ViewerCommand
import com.ichi2.anki.reviewer.MappableBinding.Companion.toPreferenceString
import com.ichi2.preferences.ControlPreference

class ControlsSettingsFragment : SettingsFragment() {
    override val preferenceResource: Int
        get() = R.xml.preferences_controls
    override val analyticsScreenNameConstant: String
        get() = "prefs.controls"

    override fun initSubscreen() {
        addAllControlPreferencesToScreen(preferenceScreen)
    }

    /**
     * Creates [PreferenceCategory] elements for each [CommandGroup] and adds
     * all [ViewerCommand] elements as [ControlPreference] to their respective category
     */
    fun addAllControlPreferencesToScreen(screen: PreferenceScreen) {
        // Create a category for each command group
        val categoryMap = CommandGroup.values().associateWith { group ->
            PreferenceCategory(screen.context).apply {
                setTitle(group.resourceId)
                key = getCategoryKey(group)
                screen.addPreference(this)
            }
        }

        // Add each command to its respective category
        for (command in ViewerCommand.values()) {
            val category = categoryMap[command.group] ?: continue
            val preference = ControlPreference(category.context).apply {
                setTitle(command.resourceId)
                key = command.preferenceKey
                setDefaultValue(command.defaultValue.toPreferenceString())
            }
            category.addPreference(preference)
        }
    }

    companion object {
        /** Returns a unique key for the preference category based on [CommandGroup] */
        fun getCategoryKey(group: CommandGroup): String = "controls_category_${group.name.lowercase()}"
    }
}"}

