package com.ichi2.anki.preferences

import androidx.fragment.app.commitNow
import androidx.test.core.app.ActivityScenario
import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.R
import com.ichi2.anki.RobolectricTest
import com.ichi2.anki.cardviewer.CommandGroup
import com.ichi2.anki.cardviewer.ViewerCommand
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.equalTo
import org.junit.Test
import org.junit.runner.RunWith

@RunWith(AndroidJUnit4::class)
class ControlsSettingsFragmentTest : RobolectricTest() {

    /**
     * Ensures all [ViewerCommand] entries have a group assigned and are displayed in the UI.
     * This test verifies that when new commands are added, they are properly categorized.
     */
    @Test
    fun allCommandsHaveGroupsAssigned() {
        // Verify all commands have a non-null group
        for (command in ViewerCommand.values()) {
            assertThat(
                "Command ${command.name} should have a group assigned",
                command.group in CommandGroup.values(),
                equalTo(true)
            )
        }
    }

    /**
     * Ensures all [ViewerCommand] entries are added to the preferences screen.
     * This validates that the programmatic addition of commands covers all cases.
     */
    @Test
    fun allCommandsAreAddedToPreferencesScreen() {
        val activityScenario = ActivityScenario.launch(Preferences::class.java)

        activityScenario.onActivity { activity ->
            val fragment = ControlsSettingsFragment()
            activity.supportFragmentManager.commitNow {
                add(R.id.settings_container, fragment)
            }

            val screen = fragment.preferenceScreen
            val allCommandKeys = ViewerCommand.values().map { it.preferenceKey }.toSet()
            val foundKeys = mutableSetOf<String>()

            // Search recursively through all preference groups to find control preferences
            fun collectKeys(group: androidx.preference.PreferenceGroup) {
                for (i in 0 until group.preferenceCount) {
                    val pref = group.getPreference(i)
                    if (pref is com.ichi2.preferences.ControlPreference) {
                        foundKeys.add(pref.key)
                    } else if (pref is androidx.preference.PreferenceGroup) {
                        collectKeys(pref)
                    }
                }
            }
            collectKeys(screen)

            val missingCommands = allCommandKeys - foundKeys
            assertThat(
                "All ViewerCommands should be present in the preferences screen. " +
                    "Missing: $missingCommands",
                missingCommands.isEmpty(),
                equalTo(true)
            )
        }
    }

    /**
     * Ensures all [CommandGroup] categories are used by at least one command
     */
    @Test
    fun allGroupsAreUsed() {
        val usedGroups = ViewerCommand.values().map { it.group }.toSet()
        val allGroups = CommandGroup.values().toSet()
        val unusedGroups = allGroups - usedGroups

        assertThat(
            "All CommandGroups should be used by at least one command. Unused: $unusedGroups",
            unusedGroups.isEmpty(),
            equalTo(true)
        )
    }

    /**
     * Ensures category keys are correctly generated
     */
    @Test
    fun categoryKeysAreCorrectlyGenerated() {
        for (group in CommandGroup.values()) {
            val key = ControlsSettingsFragment.getCategoryKey(group)
            assertThat(
                "Category key for ${group.name} should follow naming convention",
                key,
                equalTo("controls_category_${group.name.lowercase()}")
            )
        }
    }
}
